        '

            DROP TABLE IF EXISTS [mig].[baseCalculationPosition]
            CREATE TABLE [mig].[baseCalculationPosition] (
                [hourlyRate]                FLOAT               NULL,
                [calculatedRegularOutput]   FLOAT               NULL,
                [referencePrice]            DECIMAL(20,5)       NULL,
                [mainCode]                  NVARCHAR(100)       NULL,
                [mainCodeBez]               NVARCHAR(1000)      NULL,
                [turnus]                    NVARCHAR(100)       NULL,
                [mainCodeId]                INT                 NULL,
                [turnusId]                  INT                 NULL
            )
            

            DECLARE @itemList NVARCHAR(MAX)
    
	        SELECT @itemList = [value]
	        FROM OPENJSON(@json,'$')

            INSERT INTO [mig].[baseCalculationPosition]
                   ([hourlyRate]
                   ,[calculatedRegularOutput]
                   ,[referencePrice]
                   ,[mainCode]
                   ,[mainCodeBez]
                   ,[turnus])
            SELECT 
                js.[hourlyRate]
                ,js.[calculatedRegularOutput]
                ,js.[referencePrice]
                ,js.[mainCode]
                ,js.[mainCodeBez]
                ,js.[turnusCode]
            FROM 
            (
                SELECT 
                    bc.[calculatedRegularOutput],
                    bc.[hourlyRate],
                    bc.[referencePrice],
                    bc.[mainCode],
                    bc.[mainCodeBez],
                    bc.[turnusCode]
                FROM
                (
                    SELECT 
	                    maincode AS [mainCode],
                        maincodebez AS [mainCodeBez],
		                turnuscode AS [turnusCode],
                        richtleistung AS [calculatedRegularOutput],
                        stundensatz as [hourlyRate],
                        referenzpreis as [referencePrice]
                    FROM OPENJSON(@itemList)
	                    WITH (  maincode NVARCHAR(10),
                                maincodebez NVARCHAR(1000),
                                turnuscode NVARCHAR(10),
		                        richtleistung NUMERIC(10,5),
                                stundensatz NUMERIC(10,5),
                                referenzpreis DECIMAL(20,5)
			                )
                ) bC
                --INNER JOIN [dlm].[MainCode] mc
                --    ON RIGHT('00' + mc.[code],3) = RIGHT('00' + bc.[mainCode],3)
                --INNER JOIN [std].[turnus] t
                --    ON RIGHT('0' + t.[code],2) = RIGHT('0' + bC.[turnusCode],2)
            ) js


            SET @rowCount = @@ROWCOUNT

            PRINT '      ' + CAST(@rowcount AS NVARCHAR) + ' records'

            UPDATE t1
            SET t1.[mainCodeId] = t2.[id]
            FROM [mig].[baseCalculationPosition] t1
            INNER JOIN [dlm].[mainCode] t2
                ON RIGHT('00' + t2.[code],3) = RIGHT('00' + t1.[mainCode],3)

            UPDATE t1
            SET t1.[turnusId] = t2.[id]
            FROM [mig].[baseCalculationPosition] t1
            INNER JOIN [std].[turnus] t2
                ON RIGHT('0' + t2.[code],2) = RIGHT('0' + t1.[turnus],2)


            --SELECT * FROM [mig].[baseCalculationPosition]



        END--   fill master baseCalculation

		BEGIN-- fill wageGroup 

            SET @msg = '    fill wageGroup' 

            PRINT @msg
            
            --SELECT DISTINCT [maincode]  AS [lgid],[maincodebez],[hourlyRate] FROM [mig].[baseCalculationPosition]

			INSERT INTO [std].[wageGroup] ([code],[name],[isLegacy],[isDeleted],[insertedAt],[insertedBy])
			SELECT DISTINCT
				mc.[code] AS [code]
				,SUBSTRING(mc.[code] + ' - ' + LTRIM(RTRIM(mc.[description])),1,200) AS [name]
				,1
				,0
				,GETDATE()
				,1
			FROM [dlm].[mainCode] mc
				LEFT OUTER JOIN
				(
					SELECT (CAST([maincode] AS INT) / 100) * 100  AS [lgid],[hourlyRate] FROM [mig].[baseCalculationPosition]
				) q
				ON mc.[code] = q.[lgid]
			WHERE LEN(mc.[code]) = 3 AND RIGHT(mc.[code],2) = '00' AND ISNUMERIC(mc.[code]) = 1


            SET @rowCount = @@ROWCOUNT

            PRINT '      ' + CAST(@rowcount AS NVARCHAR) + ' records'

            SET @msg = '    update Maincode' 

            PRINT @msg

            UPDATE T1 
			SET 
				T1.[wageGroupId] = T2.[id]
				,T1.[updatedAt] = GETDATE()
				,T1.[updatedBy] = 1
			FROM [dlm].[mainCode] T1
			INNER JOIN [std].[wageGroup] T2
				ON CAST(T2.[code] AS INT) =  
				CASE
					WHEN ISNUMERIC(T1.[code]) = 1 THEN 	(CAST(T1.[code] AS INT) / 100) * 100 
					ELSE 0
				END
			WHERE ISNUMERIC(T1.[code]) = 1
			AND ISNUMERIC(T2.[code]) = 1

            SET @rowCount = @@ROWCOUNT


            PRINT '      ' + CAST(@rowcount AS NVARCHAR) + ' records'

		END-- wageGroup

        BEGIN-- fill wageCluster - Update MainCode

            SET @msg = '   fill wageGroup - Update MainCode'
			
            DECLARE @hourlyRate FLOAT
            DECLARE @wageGroupId INT
			DECLARE @wageGroupName NVARCHAR(200)
			DECLARE @mainCodeGroupId INT
            DECLARE @currencyId INT = (SELECT [id] FROM [std].[currency] WHERE [code] = 'EUR')
            DECLARE cMig CURSOR FOR 

			SELECT DISTINCT 
					mc.[code] AS [id]
					,wg.[id] AS [wageGroupId]
					,MAX(SUBSTRING(mc.[code] + ' - ' + LTRIM(RTRIM(mc.[Description])) +  ISNULL(' (' + REPLACE(CAST(q.[hourlyRate] AS NVARCHAR(10)),'.',',') + ' EUR/h)',''),1,200)) AS [name]
					,MAX(q.[hourlyRate]) AS [hourlyRate]
				FROM [dlm].[mainCode] mc
				INNER JOIN [std].[wageGroup] wg
					ON wg.[code] = mc.[code]
				LEFT OUTER JOIN
				(
					SELECT (CAST([maincode] AS INT) / 100) * 100  AS [lgid],[hourlyRate] FROM [mig].[baseCalculationPosition]
				) q
				ON mc.[code] = q.[lgid]
				GROUP BY mc.[code],wg.[id]

            OPEN cMig
            FETCH NEXT FROM cMig INTO @mainCodeGroupId,@wageGroupId,@wageGroupName,@hourlyRate
            WHILE @@FETCH_STATUS = 0
            BEGIN

                INSERT INTO [std].[wageCluster] ([name],[hourlyRate],[currencyId],[wageGroupId],[isLegacy],[isDeleted],[insertedAt],[insertedBy])
                SELECT SUBSTRING( N'Lohncluster ' + LTRIM(RTRIM(@wageGroupName)) + ' Stundensatz ' + ISNULL(CAST(@hourlyRate AS NVARCHAR),'- '),1,200),@hourlyRate,@currencyId,@wageGroupId,1,0,GETDATE(),1
				WHERE ISNULL(@hourlyRate,0) <> 0

                FETCH NEXT FROM cMig INTO @mainCodeGroupId,@wageGroupId,@wageGroupName,@hourlyRate

            END
            CLOSE cMig
            DEALLOCATE cMig
			
            PRINT @msg


        END-- fill wageCluster

        BEGIN --   update servicePositions (calculatedRegularOutput)

            SET @msg = '   update servicePositions (calculatedRegularOutput)'

            PRINT @msg

            UPDATE sp
                SET 
                    sp.[calculatedRegularOutput] = mbcp.[calculatedRegularOutput]
					,sp.[updatedAt] = GETDATE()
					,sp.[updatedBy] = 1
            FROM [dlm].[servicePosition] sp
            INNER JOIN 
            (
                SELECT 
                    [mainCodeId]
                    ,[turnusId]
                    ,[calculatedRegularOutput]
                    ,[referencePrice]
                FROM [mig].[baseCalculationPosition]
            ) mbcp
                ON mbcp.[mainCodeId] = sp.[mainCodeId]
                AND mbcp.[turnusId] = sp.[turnusId]

            SET @rowCount = @@ROWCOUNT

            PRINT '      ' + CAST(@rowcount AS NVARCHAR) + ' records'

        END --   update servicePositions (calculatedRegularOutput)

		BEGIN -- update wagegroupname

			UPDATE t1
				SET t1.[name] = t2.[name]
			FROM [std].[wageGroup] t1
			INNER JOIN (
				SELECT 
					wg.[id],
					wg.[code],
					mcg.[name]
				FROM [std].[wageGroup] wg
				INNER JOIN (
					SELECT 
						RIGHT(N'00'+ CAST(dmcg.[id] AS NVARCHAR),3) AS [id]
						,dtd.[Text] AS [name]
						FROM [archiv].[dbo_MainCodeGroup] dmcg
						INNER JOIN [archiv].[dbo_TextDetail] dtd
							ON dtd.[Id] = dmcg.[NameTextId]
						WHERE dtd.[Lcid] = 1031
				) mcg
				ON mcg.[id] = wg.[code]
			) t2
			ON t2.[id] = t1.[id]

            SET @rowCount = @@ROWCOUNT

            PRINT '      ' + CAST(@rowcount AS NVARCHAR) + ' records'

		END --update wagegroupname

    END TRY
    BEGIN CATCH

        SET @msg = ERROR_MESSAGE() + ' '  + @msg + ' wage.sql'
        RAISERROR(@msg,1,16)

    END CATCH

END --fill baseCalculationPosition
GO

